function genId(p){ return p+(Math.random().toString(36).substr(2,9)); }
const raw = $input.first().json;
const body = raw.body || raw;
const pl = body.payload || {};
const msg = body.message || pl.item_description || "";
let action = body.action || "";
if(!action){
  if(pl.supplier_replies && pl.supplier_replies.length>0) action="compare_quotes";
  else if(body.approved===true || pl.approved===true || pl.approval_id) action="create_purchase_order";
  else if(/aprovar|approved/.test(msg.toLowerCase())) action="request_approval";
  else action="intake";
}
const out = {
  runtime_mode: body.runtime_mode||"MOCK",
  correlation_id: body.correlation_id||genId("cmp_"),
  request_id: body.request_id||genId("req_"),
  source: body.source||"manual",
  user: body.user||{id:"",name:"",role:"",department:""},
  message: msg,
  action: action,
  payload: {
    op_id: pl.op_id||"",
    item_description: pl.item_description||msg,
    quantity: pl.quantity||null,
    unit: pl.unit||"",
    deadline: pl.deadline||"",
    max_budget: pl.max_budget||0,
    preferred_suppliers: pl.preferred_suppliers||[],
    approved: body.approved||pl.approved||false,
    approval_id: pl.approval_id||"",
    supplier_replies: pl.supplier_replies||[]
  },
  metadata: body.metadata||{}
};
return [{json:out}];

const d = $input.first().json;
const pl = d.payload || {};
const action = d.action || "intake";
const desc = pl.item_description || d.message || "";
const descL = desc.toLowerCase();

// EX/INMETRO: detectar antes de qualquer validacao - apenas logar, nao bloquear
const exInmetro = /\bex\b|area classificada|inmetro|zona explosiva|classificada ex|zona 1|zona 2/.test(descL);
d._ex_inmetro = exInmetro;

// Acoes que nao precisam de validacao completa
if(["create_purchase_order","request_approval","compare_quotes","supplier_reply"].includes(action)){
  d._validation = {valid:true, missing:[]};
  d._needs_info = false;
  return [{json:d}];
}

// Para EX/INMETRO: nao bloquear por missing unit - apenas marcar para aprovacao
if(exInmetro){
  d._validation = {valid:true, missing:[]};
  d._needs_info = false;
  return [{json:d}];
}

const missing = [];
if(!desc) missing.push("item_description");

// Unit: aceitar do payload OU do texto
const unitInDesc = /\d+\s*(un|unidade|unidades|kg|metro|m2|chapa|pecas?)/i.test(desc);
if(!pl.unit && !unitInDesc) missing.push("unit");

// Quantity: aceitar do payload OU qualquer numero no texto
const hasNum = /\d+/.test(desc);
if(!pl.quantity && !hasNum) missing.push("quantity");

const isChapa = /chapa|galvanizada|inox|aco/.test(descL);
if(isChapa){
  const hasThk = /\d+[,.]?\d*/.test(desc);
  if(!hasThk) missing.push("espessura");
  const hasDim = /\d+\s*[xX]\s*\d+/.test(desc);
  const hasQtyUnit = /\d+\s*(un|unidade|unidades|chapa|peca)/i.test(desc);
  if(!hasDim && !hasQtyUnit && !pl.quantity) missing.push("dimensoes");
}

d._validation = {valid:missing.length===0, missing};
d._needs_info = missing.length > 0;
return [{json:d}];

const d = $input.first().json;
const desc = (d.payload?.item_description || d.message || "").toLowerCase();
const pl = d.payload || {};
const mat = {};
mat.raw_description = desc;

// Thickness
const thk = desc.match(/(\d+)[,.](\d+)/);
mat.thickness = thk ? `${thk[1]}.${thk[2]}` : null;

// Dimensions
const dim = desc.match(/(\d+)\s*[xX]\s*(\d+)/);
mat.dimensions = dim ? dim[0] : null;

// Quantity from payload or text
const qtyText = desc.match(/(\d+)\s*(un|unidade|unidades|chapa|pecas?|peca)/i);
mat.quantity = pl.quantity || (qtyText ? parseInt(qtyText[1]) : null);
mat.unit = pl.unit || (qtyText ? qtyText[2].replace(/s$/,"") : "unidade");

// Material classification
if(/galvanizada|galv/.test(desc)) { mat.material_name="Chapa Galvanizada"; mat.material_category="chapa_metalica"; mat.finish="galvanizado"; }
else if(/inox/.test(desc)) { mat.material_name="Chapa Inox"; mat.material_category="chapa_metalica"; mat.finish="inox"; }
else if(/chapa.*aco|aco.*chapa/.test(desc)) { mat.material_name="Chapa de Aco"; mat.material_category="chapa_metalica"; mat.finish="aco"; }
else if(/chapa fina/.test(desc)) { mat.material_name="Chapa Fina"; mat.material_category="chapa_metalica"; mat.finish=""; }
else { mat.material_name=desc.substring(0,50); mat.material_category="generico"; mat.finish=""; }

// OP
const opM = desc.match(/\bop[\s_]?(\d+)/i) || (pl.op_id||"").match(/(\d+)/);
mat.op_id = pl.op_id || (opM ? opM[0].replace(/\s/,"") : "");

mat.urgency = /urgent|urgente|atrasad/.test(desc) ? "alta" : "normal";
mat.max_budget = pl.max_budget||0;
mat.deadline = pl.deadline||"";

// SKU
const thkCode = mat.thickness ? mat.thickness.replace(".","") : "X";
const dimCode = mat.dimensions ? mat.dimensions.replace(/\s/g,"") : "X";
const catCode = mat.material_category.toUpperCase().replace(/_/g,"");
mat.material_id = `MAT-${catCode}-${thkCode}`.substring(0,30);
mat.sku_code = `SKU-${catCode}-${thkCode}-${dimCode}`.substring(0,40);
mat.confidence = mat.material_name && mat.thickness ? 0.90 : 0.60;

d._material = mat;
return [{json:d}];

