    {id:"F001",name:"Fornecedor Aco Rio",category:"chapa_metalica",active:true,avg_days:5,score:4.5,contact:"aço@rio.com.br"},
    {id:"F002",name:"Metalurgica Brasil",category:"chapa_metalica",active:true,avg_days:7,score:4.2,contact:"compras@metbr.com.br"},
    {id:"F003",name:"Chapas Sul",category:"chapa_metalica",active:true,avg_days:4,score:4.7,contact:"vendas@chapassul.com.br"},
    {id:"F004",name:"Fornecedor Backup Ltda",category:"generico",active:true,avg_days:10,score:3.8,contact:"backup@email.com"}
  ];
  history = [
    {material_id:mat.material_id,date:"2025-01",unit_price:45.50,supplier:"F001"},
    {material_id:mat.material_id,date:"2025-02",unit_price:46.80,supplier:"F003"},
    {material_id:mat.material_id,date:"2025-03",unit_price:44.90,supplier:"F002"}
  ];
  if(mat.op_id) op = {id:mat.op_id,status:"em_andamento",deadline:mat.deadline||"2025-06-30"};
}
const avg = history.length ? history.reduce((s,h)=>s+h.unit_price,0)/history.length : 0;
d._suppliers = suppliers;
d._price_history = history;
d._avg_price = avg;
d._kanban_op = op;
return [{json:d}];

const d = $input.first().json;
const all = d._suppliers || [];
const compatible = all.filter(s => s.active && (s.category === (d._material||{}).material_category || s.category === "generico"));
const selected = compatible.sort((a,b)=>(b.score||0)-(a.score||0)).slice(0,5);
let risk = "low";
if(selected.length < 3){ risk="medium"; d._policy_override={requires_approval:true,reason:"Menos de 3 fornecedores disponiveis"}; }
d._selected_suppliers = selected;
d._supplier_risk = risk;
return [{json:d}];

const d = $input.first().json;
const mat = d._material || {};
const suppliers = d._selected_suppliers || [];
const pl = d.payload;
const opRef = mat.op_id ? ` - OP ${mat.op_id}` : "";
const subject = `Solicitacao de Cotacao - ${mat.material_name||"Material"} - Qtd: ${mat.quantity||pl.quantity||"Ver abaixo"}${opRef}`;
const body = `Prezado Fornecedor,

Solicitamos cotacao para o item abaixo:

Descricao: ${mat.material_name||pl.item_description}
Espessura: ${mat.thickness||"A confirmar"}
Dimensoes: ${mat.dimensions||"A confirmar"}
Quantidade: ${mat.quantity||pl.quantity||"A confirmar"} ${mat.unit||pl.unit||"unidades"}
Prazo desejado: ${mat.deadline||"A combinar"}

Por favor informar:
- Preco unitario e total
- Frete CIF/FOB
- Prazo de entrega
- Forma de pagamento
- Validade da cotacao
- Anexar PDF se possivel

Ref.: ${d.correlation_id} / ${d.request_id}

Aguardamos retorno.

Equipe de Compras - Vesper/Vent Rio`;
d._quotation = {
  quote_id: "qt_mock_"+(Math.random().toString(36).substr(2,8)),
  subject: subject,
  email_body: body,
  suppliers_count: suppliers.length,
  status: "draft",
  created_at: new Date().toISOString(),
  note: d.runtime_mode==="PORTAL" ? "TODO: POST /api/compras/cotacoes no Portal" : "MOCK: email nao enviado"
};
d._status = "quote_ready";
return [{json:d}];

const d = $input.first().json;
const pl = d.payload;
let replies = pl.supplier_replies||[];
if(replies.length===0){
  const avg = d._avg_price||45;
  replies = [
    {supplier_id:"F001",supplier_name:"Fornecedor Aco Rio",unit_price:avg*1.02,total_price:avg*1.02*(d._material?.quantity||10),freight:150,delivery_days:5,payment_terms:"30dd",quote_validity:30,observations:""},
    {supplier_id:"F002",supplier_name:"Metalurgica Brasil",unit_price:avg*0.98,total_price:avg*0.98*(d._material?.quantity||10),freight:200,delivery_days:7,payment_terms:"28dd",quote_validity:30,observations:"Melhor preco"},
    {supplier_id:"F003",supplier_name:"Chapas Sul",unit_price:avg*1.05,total_price:avg*1.05*(d._material?.quantity||10),freight:0,delivery_days:4,payment_terms:"30dd",quote_validity:15,observations:"Frete gratis"}
  ];
}
d._supplier_replies = replies;
return [{json:d}];

const d = $input.first().json;
const replies = d._supplier_replies || [];
if(replies.length === 0){
  d._comparison = {ranking:[], recommended_supplier:"", note:"Sem respostas de fornecedores para comparar"};
  d._status = "waiting_suppliers";
  d._risk_level = d._ex_inmetro ? "critical" : "low";
  d._requires_approval = d._ex_inmetro || false;
  return [{json:d}];
}
const qty = (d._material && d._material.quantity) || d.payload?.quantity || 1;
const avg = d._avg_price || 0;

const scored = replies.map(r=>{
  const total = r.total_price || (r.unit_price * qty);
  const priceScore = avg > 0 ? Math.max(0, 10 - ((r.unit_price - avg) / avg) * 10) : 5;
  const timeScore = Math.max(0, 10 - (r.delivery_days || 7) / 2);
  const score = parseFloat((priceScore * 0.6 + timeScore * 0.4).toFixed(2));
  const vsHist = avg > 0 ? parseFloat(((r.unit_price - avg) / avg * 100).toFixed(1)) : 0;
  return {...r, total_price: total, score, vs_history_pct: vsHist, rank: 0};
});
scored.sort((a,b) => b.score - a.score);
scored.forEach((r,i) => r.rank = i+1);
const best = scored[0] || {};
const highPrice = avg > 0 && best.unit_price > avg * 1.15;
d._comparison = {
  ranking: scored,
  recommended_supplier: best.supplier_name||"",
  recommended_supplier_id: best.supplier_id||"",
  best_price: best.unit_price||0,
  best_total: best.total_price||0,
  best_delivery: best.delivery_days||0,
  avg_market_price: avg,
  price_vs_history: best.vs_history_pct||0,
  high_price_alert: highPrice,
  generated_at: new Date().toISOString()
};
d._risk_level = d._ex_inmetro ? "critical" : (highPrice ? "high" : (d._supplier_risk||"low"));
d._requires_approval = highPrice || d._ex_inmetro || (d._policy_override?.requires_approval||false);
d._approval_reason = highPrice ? `Preco ${best.vs_history_pct}% acima da media historica` : (d._ex_inmetro ? "Material EX/INMETRO - revisao tecnica obrigatoria" : "");
d._status = "comparison_ready";
return [{json:d}];

const d = $input.first().json;
const mode = d.runtime_mode;
const best = d._comparison?.ranking?.[0]||{};
const apprId = "appr_compras_"+(Math.random().toString(36).substr(2,8));
