  created_at: new Date().toISOString()
};
d._status = "purchase_order_draft";
d._portal_synced = false;
return [{json:d}];

const d = $input.first().json;

// Aplicar risco EX/INMETRO em qualquer caminho
if(d._ex_inmetro) {
  d._risk_level = "critical";
  d._requires_approval = true;
