  timestamp: new Date().toISOString(),
  note: d.runtime_mode === "PORTAL" ? "TODO: POST /api/automation/audit" : "MOCK: audit_logged=true"
};
return [{json:d}];

const d = $input.first().json;
d._status = "needs_info";
d._risk_level = "low";
const questions = [];
const miss = d._validation?.missing||[];
if(miss.includes("item_description")) questions.push("Qual item deseja comprar?");
if(miss.includes("quantity")) questions.push("Qual a quantidade necessaria?");
if(miss.includes("unit")) questions.push("Qual a unidade (unidade, kg, metro)?");
