const d = $input.first().json;
const replies = d._supplier_replies || [];
if(replies.length === 0){
  d._comparison = {ranking:[], recommended_supplier:"", note:"Sem respostas de fornecedores para comparar"};
  d._status = "waiting_suppliers";
  d._risk_level = d._ex_inmetro ? "critical" : "low";
  d._requires_approval = d._ex_inmetro || false;
  return [{json:d}];
}
const qty = (d._material && d._material.quantity) || d.payload?.quantity || 1;
const avg = d._avg_price || 0;

const scored = replies.map(r=>{
  const total = r.total_price || (r.unit_price * qty);
  const priceScore = avg > 0 ? Math.max(0, 10 - ((r.unit_price - avg) / avg) * 10) : 5;
  const timeScore = Math.max(0, 10 - (r.delivery_days || 7) / 2);
  const score = parseFloat((priceScore * 0.6 + timeScore * 0.4).toFixed(2));
  const vsHist = avg > 0 ? parseFloat(((r.unit_price - avg) / avg * 100).toFixed(1)) : 0;
  return {...r, total_price: total, score, vs_history_pct: vsHist, rank: 0};
});
scored.sort((a,b) => b.score - a.score);
scored.forEach((r,i) => r.rank = i+1);
const best = scored[0] || {};
const highPrice = avg > 0 && best.unit_price > avg * 1.15;
d._comparison = {
  ranking: scored,
  recommended_supplier: best.supplier_name||"",
  recommended_supplier_id: best.supplier_id||"",
  best_price: best.unit_price||0,
  best_total: best.total_price||0,
  best_delivery: best.delivery_days||0,
  avg_market_price: avg,
  price_vs_history: best.vs_history_pct||0,
